#[%dw 2.0
output application/json
---
{
    step: "After list laboratory results files",
    data: {
        business: {
        	countFiles: sizeOf(payload.attributes)
        },
        technical: {}
    }
}]

#[%dw 2.0
output application/json
---
{
    step: "Debug list laboratory results files",
    data: {
        business: {
        	patientFile: "$(vars.patientId).csv"
        },
        technical: {
        	firstFile: payload[0].attributes.fileName,
        	patientFileExists: payload.attributes.fileName contains "$(vars.patientId).csv"
        }
    }
}]

#[%dw 2.0
output application/json
---
{
    step: "After retrieve results",
    data: {
        business: {
        	patientFile: "$(vars.patientId).csv",
        	countResults: sizeOf(payload)
        },
        technical: {}
    }
}]

#[%dw 2.0
output application/json indent=false
---
{
    step: "Debug retrieve results",
    data: {
        business: {},
        technical: {
        	firstResult: payload[0]
        }
    }
}]
